import React, { useEffect, useState, useMemo } from 'react';
import { getDashboardOverview } from '../services/dashboardService';
import { DashboardOverview, DailyBias } from '../types';
import Spinner from './Spinner';
import ErrorDisplay from './ErrorDisplay';
import { usePageData } from '../hooks/usePageData';
import { useNavigate } from 'react-router-dom';
import SeasonalModeToggle from './SeasonalModeToggle';

const safeText = (val: any): string => {
    if (val === null || val === undefined) return '';
    if (typeof val === 'string') return val;
    if (typeof val === 'number') return String(val);
    try {
        if (typeof val === 'object') {
            const keys = Object.keys(val);
            if (keys.length === 1) return String(val[keys[0]]);
            return JSON.stringify(val);
        }
        return String(val);
    } catch (e) {
        return 'Data Error';
    }
};

const MarketPulseTicker: React.FC<{ overview: DashboardOverview }> = ({ overview }) => {
    const tickerItems = useMemo(() => {
        const items = [
            `GLOBAL SENTIMENT: ${overview.marketCondition.sentiment}`,
            `VOLATILITY: ${overview.marketCondition.volatility}`,
            `ACTIVE SESSION: ${overview.marketCondition.dominantSession}`,
            `PRIMARY DRIVER: ${overview.marketCondition.marketDriver}`,
            ...overview.marketCondition.trendingPairs.map(p => `${p.name}: ${p.strength} TREND`)
        ];
        return [...items, ...items]; // Duplicate for seamless loop
    }, [overview]);

    return (
        <div className="w-full bg-black/40 border-y border-white/10 overflow-hidden py-2 select-none">
            <div className="flex whitespace-nowrap animate-ticker">
                {tickerItems.map((item, idx) => (
                    <div key={idx} className="flex items-center mx-8">
                        <span className="text-[10px] font-black text-red-500 uppercase tracking-widest mr-3">● Pulse</span>
                        <span className="text-[10px] font-bold text-gray-400 uppercase tracking-[0.15em]">{item}</span>
                    </div>
                ))}
            </div>
            <style>{`
                @keyframes ticker {
                    0% { transform: translateX(0); }
                    100% { transform: translateX(-50%); }
                }
                .animate-ticker {
                    animation: ticker 40s linear infinite;
                }
            `}</style>
        </div>
    );
};

const Card: React.FC<{ title: string; children: React.ReactNode; className?: string; icon?: string, isSeasonalGlow?: boolean; }> = ({ title, children, className = "", icon, isSeasonalGlow }) => (
    <div className={`relative bg-white/30 dark:bg-black/40 backdrop-blur-2xl border border-white/20 rounded-[2rem] shadow-2xl flex flex-col hover:shadow-red-500/5 transition-all duration-500 group ${className} ${isSeasonalGlow ? 'seasonal-glow' : ''}`}>
        {isSeasonalGlow && <div className="seasonal-badge">🟢 Seasonal Bias Active</div>}
        <div className="p-6 flex items-center justify-between">
            <h2 className="text-xs font-black text-gray-900 dark:text-white uppercase tracking-[0.2em] flex items-center gap-3">
                {icon && <i className={`${icon} text-red-600 dark:text-red-500 text-sm`}></i>}
                {title}
            </h2>
            <div className="w-2 h-2 rounded-full bg-red-500/20 group-hover:bg-red-500/50 transition-colors"></div>
        </div>
        <div className="p-6 pt-0 flex-1">
            {children}
        </div>
    </div>
);

const SentimentBadge: React.FC<{ value?: string }> = ({ value }) => {
    if (!value) return null;
    const displayValue = safeText(value);
    let colorClass = "bg-gray-500/10 text-gray-500 border-gray-500/20";
    if (displayValue === 'Bullish') colorClass = "bg-green-500/10 text-green-700 dark:text-green-400 border-green-500/30";
    if (displayValue === 'Bearish') colorClass = "bg-red-500/10 text-red-700 dark:text-red-400 border-red-500/30";

    return (
        <span className={`px-3 py-1 rounded-xl text-xs font-black uppercase tracking-widest border border-white/10 backdrop-blur-md shadow-sm ${colorClass}`}>
            {displayValue}
        </span>
    );
};

const DailyBiasCard: React.FC<{ biases?: DailyBias[], isSeasonal: boolean }> = ({ biases, isSeasonal }) => {
    const [currentIndex, setCurrentIndex] = useState(0);
    const [fade, setFade] = useState(false);

    const safeBiases = Array.isArray(biases) ? biases : [];

    useEffect(() => {
        if (safeBiases.length === 0) return;
        const interval = setInterval(() => {
            triggerTransition();
        }, 60000);
        return () => clearInterval(interval);
    }, [safeBiases.length]);

    const triggerTransition = (nextIndex?: number) => {
        if (safeBiases.length === 0) return;
        setFade(true);
        setTimeout(() => {
            setCurrentIndex(prev => nextIndex !== undefined ? nextIndex : (prev + 1) % safeBiases.length);
            setFade(false);
        }, 300);
    };

    if (safeBiases.length === 0) return (
        <div className="bg-black/20 backdrop-blur-xl border border-white/20 rounded-[2.5rem] p-8 text-white h-full flex items-center justify-center">
            <p className="font-black uppercase tracking-widest opacity-30">Neural Sync Required</p>
        </div>
    );

    const currentBias = safeBiases[currentIndex] || safeBiases[0];
    const displayBias = safeText(currentBias.bias);
    const isBullish = displayBias === 'Bullish';
    const isBearish = displayBias === 'Bearish';

    const gradientClass = isBullish 
        ? "from-green-600/90 to-emerald-800/90" 
        : isBearish 
            ? "from-red-600/90 to-rose-800/90" 
            : "from-blue-600/90 to-indigo-800/90";

    const strengthBadgeClass = isBullish 
        ? "bg-green-400/20 text-green-100 border-green-400/30" 
        : isBearish 
            ? "bg-red-400/20 text-red-100 border-red-400/30" 
            : "bg-blue-400/20 text-blue-100 border-blue-400/30";

    return (
        <div 
            onClick={() => triggerTransition()}
            className={`relative cursor-pointer bg-gradient-to-br ${gradientClass} backdrop-blur-2xl border border-white/30 rounded-[2.5rem] p-8 text-white shadow-2xl h-full flex flex-col justify-between transition-all duration-500 hover:scale-[1.02] ${isSeasonal ? 'seasonal-glow' : ''}`}
        >
            {isSeasonal && <div className="seasonal-badge">🟢 Seasonal Bias Active</div>}
            <div className={`transition-opacity duration-300 ${fade ? 'opacity-0' : 'opacity-100'}`}>
                <div className="flex justify-between items-start mb-6">
                    <h3 className="font-black text-xl mb-1 flex items-center gap-3 uppercase tracking-tighter">
                        <i className="fas fa-microchip opacity-80 text-sm"></i> Neural Bias
                    </h3>
                    <div className="flex gap-1.5 p-1.5 bg-black/20 rounded-full">
                        {safeBiases.map((_, i) => (
                            <div key={i} className={`h-1.5 w-1.5 rounded-full transition-all ${i === currentIndex ? 'bg-white w-4' : 'bg-white/20'}`}></div>
                        ))}
                    </div>
                </div>

                <p className="text-white text-base font-bold leading-relaxed min-h-[4rem] drop-shadow-md">
                    {safeText(currentBias.reasoning)}
                </p>

                <div className="mt-8 pt-8 border-t border-white/20 flex justify-between items-end">
                    <div>
                        <p className="text-[10px] text-white/50 uppercase font-black tracking-widest mb-1">Pair</p>
                        <p className="text-xl font-black uppercase tracking-tighter">{safeText(currentBias.pair)}</p>
                    </div>
                    <div className="text-right">
                        <SentimentBadge value={displayBias} />
                        <div className={`mt-2 px-2 py-0.5 rounded text-[8px] font-black uppercase tracking-widest border ${strengthBadgeClass}`}>
                            {safeText(currentBias.strength)} Strength
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

