const DailyBiasCard: React.FC<{ biases?: DailyBias[], isSeasonal: boolean }> = ({ biases, isSeasonal }) => {
    const [currentIndex, setCurrentIndex] = useState(0);
    const [fade, setFade] = useState(false);

    const safeBiases = Array.isArray(biases) ? biases : [];

    useEffect(() => {
        if (safeBiases.length === 0) return;
        const interval = setInterval(() => {
            triggerTransition();
        }, 12000);
        return () => clearInterval(interval);
    }, [safeBiases.length]);

    const triggerTransition = (nextIndex?: number) => {
        if (safeBiases.length === 0) return;
        setFade(true);
        setTimeout(() => {
            setCurrentIndex(prev => nextIndex !== undefined ? nextIndex : (prev + 1) % safeBiases.length);
            setFade(false);
        }, 400);
    };

    if (safeBiases.length === 0) return (
        <div className="bg-black/20 rounded-[2.5rem] p-10 text-white h-full flex items-center justify-center border border-white/5">
            <p className="font-black uppercase tracking-[0.3em] opacity-20 text-xs">Neural Sync In Progress</p>
        </div>
    );

    const currentBias = safeBiases[currentIndex] || safeBiases[0];
    const displayBias = safeText(currentBias.bias);
    const isBullish = displayBias === 'Bullish';
    const isBearish = displayBias === 'Bearish';

    const gradientClass = isBullish 
        ? "from-emerald-600/90 to-teal-800/90" 
        : isBearish 
            ? "from-rose-600/90 to-red-800/90" 
            : "from-slate-600/90 to-slate-800/90";

    const strengthBadgeClass = isBullish 
        ? "bg-emerald-400/20 text-emerald-100 border-emerald-400/30" 
        : isBearish 
            ? "bg-rose-400/20 text-rose-100 border-rose-400/30" 
            : "bg-slate-400/20 text-slate-100 border-slate-400/30";

    return (
        <div 
            onClick={() => triggerTransition()}
            className={`relative cursor-pointer bg-gradient-to-br ${gradientClass} border border-white/20 rounded-[2.5rem] p-10 text-white shadow-2xl h-full flex flex-col justify-between transition-all duration-500 hover:scale-[1.01] ${isSeasonal ? 'seasonal-glow' : ''}`}
        >
            <div className={`transition-opacity duration-500 ${fade ? 'opacity-0' : 'opacity-100'}`}>
                <div className="flex justify-between items-start mb-8">
                    <h3 className="font-black text-2xl flex items-center gap-4 uppercase tracking-tighter">
                        <i className="fas fa-microchip opacity-70 text-base"></i> BIAS ENGINE
                    </h3>
                    <div className="flex gap-2 p-2 bg-black/30 rounded-full">
                        {safeBiases.map((_, i) => (
                            <div key={i} className={`h-1.5 w-1.5 rounded-full transition-all duration-500 ${i === currentIndex ? 'bg-white w-5' : 'bg-white/10'}`}></div>
                        ))}
                    </div>
                </div>

                <p className="text-white text-lg font-bold leading-relaxed min-h-[5rem] drop-shadow-lg">
                    {safeText(currentBias.reasoning)}
                </p>

                <div className="mt-10 pt-10 border-t border-white/10 flex justify-between items-end">
                    <div>
                        <p className="text-[11px] text-white/50 uppercase font-black tracking-widest mb-2">VECTOR</p>
                        <p className="text-2xl font-black uppercase tracking-tight">{safeText(currentBias.pair)}</p>
                    </div>
                    <div className="text-right">
                        <SentimentBadge value={displayBias} />
                        <div className={`mt-3 px-3 py-1 rounded text-[9px] font-black uppercase tracking-[0.2em] border ${strengthBadgeClass}`}>
                            {safeText(currentBias.strength)} STRENGTH
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

