const CACHE_NAME = 'grey-algo-apex-trader-cache-v3';
const urlsToCache = [
  '/',
  '/index.html',
  '/logo.svg'
];

self.addEventListener('install', event => {
  self.skipWaiting();
  event.waitUntil(
    caches.open(CACHE_NAME)
      .then(cache => {
        console.log('Opened cache');
        return cache.addAll(urlsToCache);
      })
  );
});

self.addEventListener('fetch', event => {
  const requestUrl = new URL(event.request.url);

  // CRITICAL: Always bypass service worker for API and Authentication domains
  // to prevent 'auth/network-request-failed' and ensuring fresh AI data.
  const bypassHosts = [
    'generativelanguage.googleapis.com',
    'identitytoolkit.googleapis.com',
    'securetoken.googleapis.com',
    'firestore.googleapis.com',
    'firebaseinstallations.googleapis.com',
    'www.googleapis.com'
  ];

  if (bypassHosts.some(host => requestUrl.hostname.includes(host))) {
    event.respondWith(fetch(event.request));
    return;
  }

  // For all other requests (local assets), use a cache-first strategy.
  event.respondWith(
    caches.match(event.request)
      .then(response => {
        if (response) {
          return response; // Serve from cache
        }

        return fetch(event.request).then(
          response => {
            // Only cache GET requests with 2xx status codes
            if (!response || response.status !== 200 || event.request.method !== 'GET') {
              return response;
            }

            const responseToCache = response.clone();
            caches.open(CACHE_NAME)
              .then(cache => {
                cache.put(event.request, responseToCache);
              });

            return response;
          }
        );
      })
  );
});

self.addEventListener('activate', event => {
  const cacheWhitelist = [CACHE_NAME];
  event.waitUntil(
    caches.keys().then(cacheNames => {
      return Promise.all(
        cacheNames.map(cacheName => {
          if (cacheWhitelist.indexOf(cacheName) === -1) {
            return caches.delete(cacheName);
          }
        })
      );
    })
  );
});

import React, { createContext, useState, useContext, useEffect, ReactNode } from 'react';
import { 
  signInWithPopup, 
  signInWithEmailAndPassword, 
  createUserWithEmailAndPassword, 
  signOut, 
  sendPasswordResetEmail,
  onAuthStateChanged,
  User as FirebaseUser,
  AuthError
} from 'firebase/auth';
import { auth, googleProvider } from '../services/firebaseConfig';

interface User {
  email?: string;
  plan: 'Free' | 'Pro' | 'Apex';
  isGuest?: boolean;
  uid?: string;
}

interface AuthContextType {
  user: User;
  login: (email: string, password?: string) => Promise<void>;
  loginWithGoogle: () => Promise<void>;
  signup: (email: string, password?: string) => Promise<void>;
  logout: () => void;
  resetPassword: (email: string) => Promise<void>;
  error: string | null;
  clearError: () => void;
  isLoading: boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User>({ plan: 'Free', isGuest: true });
  const [error, setError] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    if (!auth) {
      console.warn("Firebase config not found. Running in Guest Mode.");
      setIsLoading(false);
      return;
    }

    const unsubscribe = onAuthStateChanged(auth, (firebaseUser) => {
      if (firebaseUser) {
        setUser({
          email: firebaseUser.email || undefined,
          uid: firebaseUser.uid,
          plan: 'Free', // Default plan
          isGuest: false
        });
      } else {
        setUser({ plan: 'Free', isGuest: true });
      }
      setIsLoading(false);
    });

    return () => unsubscribe();
  }, []);

  const clearError = () => setError(null);

  const getFriendlyErrorMessage = (err: AuthError) => {
    console.error("Auth Error Code:", err.code);
    switch (err.code) {
        case 'auth/network-request-failed':
            return "Network error. Please check your internet connection, disable any restrictive VPNs/Firewalls, or try a different browser.";
        case 'auth/invalid-credential':
            return "Invalid login credentials. Please check your email and password.";
        case 'auth/user-not-found':
            return "Account not found. Please sign up first.";
        case 'auth/wrong-password':
            return "Incorrect password. Please try again.";
        case 'auth/email-already-in-use':
            return "That email is already in use.";
        case 'auth/weak-password':
            return "Password should be at least 6 characters.";
        case 'auth/popup-closed-by-user':
            return null;
        case 'auth/cancelled-popup-request':
            return null;
        case 'auth/operation-not-allowed':
            return "Auth method not enabled in console.";
        case 'auth/unauthorized-domain':
            return "Domain not authorized for Firebase Auth.";
        case 'auth/popup-blocked':
            return "Sign-in popup blocked. Please enable popups.";
        case 'auth/invalid-email':
            return "Invalid email address format.";
        default:
            return err.message || "Authentication failed. Please try again later.";
    }
  };

  const login = async (email: string, password?: string) => {
    setError(null);
    if (!auth) throw new Error("Firebase not configured");
    if (!password) {
      setError("Password is required.");
      return;
    }
    try {
      await signInWithEmailAndPassword(auth, email, password);
    } catch (err: any) {
      const msg = getFriendlyErrorMessage(err);
      if (msg) setError(msg);
      throw err;
    }
  };

  const loginWithGoogle = async () => {
      setError(null);
      if (!auth) return;
      try {
          await signInWithPopup(auth, googleProvider);
      } catch (err: any) {
          const msg = getFriendlyErrorMessage(err);
          if (msg) setError(msg);
          throw err;
      }
  };

  const signup = async (email: string, password?: string) => {
    setError(null);
    if (!auth) throw new Error("Firebase not configured");
    if (!password) {
        setError("Password is required.");
        return;
    }
    try {
        await createUserWithEmailAndPassword(auth, email, password);
    } catch (err: any) {
        const msg = getFriendlyErrorMessage(err);
        if (msg) setError(msg);
        throw err;
    }
  };

  const logout = async () => {
    if (auth) {
        try {
            await signOut(auth);
        } catch (e) {
            console.error("Sign out error", e);
        }
    }
    setUser({ plan: 'Free', isGuest: true });
    setError(null);
  };

  const resetPassword = async (email: string) => {
    setError(null);
    if (!auth) throw new Error("Firebase not configured");
    if (!email) {
        setError("Email is required.");
        return;
    }
    try {
        await sendPasswordResetEmail(auth, email);
    } catch (err: any) {
        const msg = getFriendlyErrorMessage(err);
        if (msg) setError(msg);
        throw err;
    }
  };

  return (
    <AuthContext.Provider value={{ user, login, loginWithGoogle, signup, logout, resetPassword, error, clearError, isLoading }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = (): AuthContextType => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

