            <div className="flex flex-col md:flex-row justify-between items-center gap-6">
                <div className="text-left w-full md:w-auto">
                    <h1 className="text-4xl font-black text-gray-900 dark:text-white uppercase tracking-tighter">Terminal Command</h1>
                    <p className="text-[11px] text-gray-500 font-bold uppercase tracking-[0.3em] mt-1">Real-time Institutional Data Stream</p>
                </div>
                <div className="w-full md:w-auto">
                    <SeasonalModeToggle />
                </div>
            </div>

            {/* MAIN GLOBAL MARKET PULSE HUB - RICH GLASSMORPHISM */}
            <div className={`relative bg-white/20 dark:bg-black/30 backdrop-blur-2xl border border-white/20 dark:border-white/5 rounded-[3rem] shadow-2xl overflow-hidden transition-all duration-700 ${isSeasonalModeActive ? 'seasonal-glow' : ''}`}>

                {/* Hub Header */}
                <div className="p-8 border-b border-white/10 flex flex-col sm:flex-row justify-between items-center gap-6 bg-gradient-to-r from-red-600/5 to-transparent">
                    <div className="flex items-center gap-4">
                        <div className="w-14 h-14 rounded-2xl bg-red-600 flex items-center justify-center text-white shadow-lg shadow-red-600/20">
                            <i className="fas fa-satellite-dish text-2xl animate-pulse"></i>
                        </div>
                        <div>
                            <h2 className="text-xl font-black text-gray-900 dark:text-white uppercase tracking-tight">Synaptic Market Pulse</h2>
                            <p className="text-[10px] text-gray-500 font-black uppercase tracking-widest flex items-center gap-2">
                                <span className="w-1.5 h-1.5 rounded-full bg-green-500 animate-ping"></span>
                                Live Feed Connected
                            </p>
                        </div>
                    </div>
                    <div className="flex gap-4">
                        <div className="bg-black/5 dark:bg-white/5 px-4 py-2 rounded-xl border border-white/5">
                            <span className="block text-[9px] text-gray-500 uppercase font-black tracking-widest mb-0.5">Global Status</span>
                            <SentimentBadge value={overview.marketCondition?.sentiment} />
                        </div>
                        <div className="bg-black/5 dark:bg-white/5 px-4 py-2 rounded-xl border border-white/5">
                            <span className="block text-[9px] text-gray-500 uppercase font-black tracking-widest mb-0.5">Volatility</span>
                            <span className="text-xs font-bold text-gray-900 dark:text-white uppercase">{safeText(overview.marketCondition?.volatility)}</span>
                        </div>
                    </div>
                </div>

                {/* Hub Content Grid */}
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-0 divide-y md:divide-y-0 md:divide-x divide-white/10">

                    {/* Column 1: Daily Bias & Trends */}
                    <div className="p-8 space-y-10">
                        {/* Daily Bias Section */}
                        <div>
                            <SectionHeader icon="fas fa-brain" title="Neural Daily Bias" />
                            {safeBiases.length > 0 ? (
                                <div className="bg-black/20 dark:bg-white/5 p-5 rounded-2xl border border-white/5 hover:border-red-500/20 transition-all cursor-pointer group" onClick={() => setBiasIndex(p => (p+1) % safeBiases.length)}>
                                    <div className="flex justify-between items-start mb-4">
                                        <span className="text-lg font-black text-gray-900 dark:text-white">{safeText(currentBias?.pair)}</span>
                                        <SentimentBadge value={currentBias?.bias} />
                                    </div>
                                    <p className="text-xs text-gray-600 dark:text-gray-400 font-medium leading-relaxed italic line-clamp-3">
                                        "{safeText(currentBias?.reasoning)}"
                                    </p>
                                    <div className="mt-4 pt-4 border-t border-white/5 flex justify-between items-center">
                                        <span className="text-[9px] font-black text-red-500 uppercase tracking-widest">{safeText(currentBias?.strength)} Strength</span>
                                        <div className="flex gap-1">
                                            {safeBiases.map((_, i) => (
                                                <div key={i} className={`h-1 w-3 rounded-full transition-all ${i === biasIndex ? 'bg-red-500' : 'bg-gray-700'}`}></div>
                                            ))}
                                        </div>
                                    </div>
                                </div>
                            ) : (
                                <p className="text-xs text-gray-500 italic">Calculating bias vectors...</p>
                            )}
                        </div>

                        {/* Trend Scanner Section */}
                        <div>
                            <SectionHeader icon="fas fa-chart-line" title="Technical Trend Scanner" />
                            <div className="space-y-3">
                                {(overview.technicalSummary?.dominantTrends || []).slice(0, 4).map((trend, i) => (
                                    <div key={i} className="flex items-center justify-between bg-black/5 dark:bg-white/5 p-3 rounded-xl border border-white/5">
                                        <span className="text-[10px] font-bold text-gray-700 dark:text-gray-300">{safeText(trend.pair)}</span>
                                        <div className="flex items-center gap-3">
                                            <span className={`text-[10px] font-black uppercase ${trend.direction === 'Uptrend' ? 'text-green-500' : trend.direction === 'Downtrend' ? 'text-red-500' : 'text-gray-500'}`}>
                                                {trend.direction}
                                            </span>
                                            <div className="flex items-end gap-0.5 h-3">
                                                {(trend.sparkline || [5, 10, 8, 15, 12, 20]).map((v, j) => (
                                                    <div key={j} className="w-1 bg-gray-500/20 rounded-full" style={{ height: `${(v / 25) * 100}%`, backgroundColor: trend.direction === 'Uptrend' ? 'rgba(34, 197, 94, 0.4)' : 'rgba(239, 68, 68, 0.4)' }}></div>
                                                ))}
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>

                    {/* Column 2: Setups & 24H Outlook */}
                    <div className="p-8 space-y-10">
                        {/* High Probability Setup */}
                        <div>
                            <SectionHeader icon="fas fa-crosshairs" title="Institutional Setup" />
                            {(overview.tradingOpportunities?.highProbabilitySetups || []).slice(0, 1).map((setup, i) => (
                                <div key={i} className="bg-gradient-to-br from-red-600 to-rose-700 p-5 rounded-2xl shadow-xl shadow-red-600/10 text-white group cursor-pointer hover:scale-[1.02] transition-transform" onClick={() => navigate('/charting')}>
                                    <div className="flex justify-between items-start mb-4">
                                        <div>
                                            <span className="text-xl font-black uppercase tracking-tight">{safeText(setup.pair)}</span>
                                            <p className="text-[9px] font-black opacity-80 uppercase tracking-widest">{safeText(setup.strategy)}</p>
                                        </div>
                                        <span className={`px-2 py-1 rounded text-[10px] font-black uppercase tracking-widest bg-white text-red-600`}>
                                            {safeText(setup.signal)}
                                        </span>
                                    </div>
                                    <div className="grid grid-cols-2 gap-4 mt-6 pt-6 border-t border-white/20">
                                        <div>
                                            <span className="block text-[8px] font-black opacity-60 uppercase tracking-widest mb-1">Target R:R</span>
                                            <span className="text-sm font-bold">{safeText(setup.rrRatio)}</span>
                                        </div>
                                        <div className="text-right">
                                            <span className="block text-[8px] font-black opacity-60 uppercase tracking-widest mb-1">Confidence</span>
                                            <span className="text-sm font-bold">{setup.confidence}%</span>
                                        </div>
                                    </div>
                                </div>
                            ))}
                            {(!overview.tradingOpportunities?.highProbabilitySetups?.length) && <p className="text-xs text-gray-500 italic">Scanning for entries...</p>}
                        </div>

                        {/* Next 24hrs Outlook */}
                        <div>
                            <SectionHeader icon="fas fa-hourglass-half" title="Next 24Hrs Outlook" />
                            <div className="space-y-3">
                                {(overview.next24hOutlook || []).slice(0, 3).map((out, i) => (
                                    <div key={i} className="bg-black/5 dark:bg-white/5 p-4 rounded-2xl border border-white/5 hover:border-white/10 transition-colors">
                                        <div className="flex justify-between items-center mb-1">
                                            <span className="text-xs font-black text-gray-900 dark:text-white uppercase">{safeText(out.pair)}</span>
                                            <SentimentBadge value={out.bias} />
                                        </div>
                                        <p className="text-[11px] text-gray-500 dark:text-gray-400 font-medium leading-relaxed">{safeText(out.outlook)}</p>
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>

                    {/* Column 3: Economic Calendar & Risk */}
                    <div className="p-8 space-y-10">
                        {/* Economic Calendar */}
                        <div>
                            <SectionHeader icon="fas fa-calendar-alt" title="Economic Calendar" />
                            <div className="space-y-4">
                                {(overview.economicData?.upcomingEvents || []).slice(0, 4).map((ev, i) => (
                                    <div key={i} className="flex gap-4 group">
                                        <div className="flex flex-col items-center">
                                            <span className="text-[10px] font-black text-red-500 uppercase">{safeText(ev.time)}</span>
                                            <div className="w-px flex-1 bg-white/10 my-1 group-last:hidden"></div>
                                        </div>
                                        <div className="flex-1 pb-4">
                                            <div className="flex justify-between items-start mb-0.5">
                                                <h4 className="text-[11px] font-bold text-gray-800 dark:text-gray-200 uppercase leading-tight line-clamp-1">{safeText(ev.event)}</h4>
                                                <span className={`text-[8px] font-black px-1.5 py-0.5 rounded ${ev.expectedImpact === 'High' ? 'bg-red-500/20 text-red-500' : 'bg-yellow-500/20 text-yellow-500'}`}>
                                                    {ev.expectedImpact}
                                                </span>
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>

                        {/* Risk Assessment Section */}
                        <div className="bg-blue-600/10 dark:bg-blue-500/5 p-6 rounded-[2rem] border border-blue-500/20">
                            <SectionHeader icon="fas fa-shield-alt" title="Risk Protocol" />
                            <div className="space-y-4">
                                <div className="flex justify-between items-center">
                                    <span className="text-[10px] font-bold text-gray-500 uppercase">Market Risk</span>
                                    <span className={`text-[10px] font-black uppercase ${overview.tradingOpportunities?.riskAssessment?.marketRisk === 'High' ? 'text-red-500' : 'text-green-500'}`}>
                                        {safeText(overview.tradingOpportunities?.riskAssessment?.marketRisk)}
                                    </span>
                                </div>
                                <div className="flex justify-between items-center">
                                    <span className="text-[10px] font-bold text-gray-500 uppercase">Neural Sizing</span>
                                    <span className="text-[10px] font-black text-blue-500 uppercase">{safeText(overview.tradingOpportunities?.riskAssessment?.positionSizing)}</span>
                                </div>
                                <div className="pt-2">
                                    <button onClick={() => navigate('/charting')} className="w-full py-3 bg-red-600 hover:bg-red-700 text-white rounded-xl text-[9px] font-black uppercase tracking-[0.2em] shadow-lg shadow-red-600/20 transition-all active:scale-95">
                                        Enter Terminal
                                    </button>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>

                {/* Hub Footer Area */}
                <div className="p-4 bg-black/40 border-t border-white/10 flex justify-between items-center">
                    <span className="text-[8px] text-gray-500 uppercase font-black tracking-widest">Aistudio Apex Oracle v4.2</span>
                    <span className="text-[8px] text-gray-500 uppercase font-black tracking-widest">Sync: {new Date(overview.lastUpdated).toLocaleTimeString()}</span>
                </div>
            </div>
        </div>
    );
};

export default Dashboard;
